// src/pages/Placement.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

export default function Placement() {
  const navigate = useNavigate();
  const currentUser = JSON.parse(localStorage.getItem("currentUser"));
  const role = currentUser?.role;

  const [placements, setPlacements] = useState([]);
  const [formData, setFormData] = useState({ title: "", company: "", package: "" });
  const [editIndex, setEditIndex] = useState(null);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("placements")) || [];
    setPlacements(stored);
  }, []);

  useEffect(() => {
    if (role === "Student") {
      toast.error("Access Denied: Students cannot access this page.");
      navigate("/dashboard");
    }
  }, [role, navigate]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleAddOrUpdate = () => {
    if (!formData.title || !formData.company || !formData.package) {
      toast.warning("Please fill all fields.");
      return;
    }

    const updated = [...placements];
    if (editIndex !== null) {
      updated[editIndex] = formData;
      toast.success("Placement updated!");
    } else {
      updated.push(formData);
      toast.success("Placement added!");
    }

    setPlacements(updated);
    localStorage.setItem("placements", JSON.stringify(updated));
    setFormData({ title: "", company: "", package: "" });
    setEditIndex(null);
  };

  const handleEdit = (index) => {
    setFormData(placements[index]);
    setEditIndex(index);
  };

  const handleDelete = (index) => {
    const updated = placements.filter((_, i) => i !== index);
    setPlacements(updated);
    localStorage.setItem("placements", JSON.stringify(updated));
    toast.info("Placement deleted!");
  };

  return (
    <div className="page">
      <ToastContainer />
      <h2>Placement Management</h2>

      {(role === "Admin" || role === "HR") && (
        <div>
          <input name="title" placeholder="Title" value={formData.title} onChange={handleChange} />
          <input name="company" placeholder="Company" value={formData.company} onChange={handleChange} />
          <input name="package" placeholder="Package" value={formData.package} onChange={handleChange} />
          <button onClick={handleAddOrUpdate}>{editIndex !== null ? "Update" : "Add"}</button>
        </div>
      )}

      <ul>
        {placements.map((placement, index) => (
          <li key={index}>
            <strong>{placement.title}</strong> at {placement.company} ({placement.package} LPA)
            {(role === "Admin" || role === "HR") && (
              <>
                <button onClick={() => handleEdit(index)}>Edit</button>
              </>
            )}
            {role === "Admin" && <button onClick={() => handleDelete(index)}>Delete</button>}
          </li>
        ))}
      </ul>
    </div>
  );
}
